export const BONGALONGA_B64 = "";

// ─── ProTracker MOD Player ───
export const ModPlayer = (() => {
  let _ctx = null, _gain = null, _mod = null;
  let _playing = false, _timerId = null;
  let _order = 0, _row = 0, _speed = 6, _bpm = 125;
  let _nextRowTime = 0;
  let _channels = [], _sampleBuffers = [];
  const SCHEDULE_AHEAD = 0.12, SCHEDULE_INTERVAL = 50;

  function periodToFreq(period) {
    return period > 0 ? 7093789.2 / (period * 2) : 0;
  }

  function parseMOD(buffer) {
    const data = new Uint8Array(buffer);
    const mod = {};
    mod.title = String.fromCharCode(...data.slice(0,20)).replace(/\0/g,'');
    const magic = String.fromCharCode(...data.slice(1080,1084));
    mod.channels = (magic==='6CHN')?6:(magic==='8CHN')?8:4;
    mod.instruments = [];
    for (let i=0;i<31;i++) {
      const b = 20+i*30;
      const length = (data[b+22]<<8|data[b+23])*2;
      const ft = data[b+24]&0xF;
      mod.instruments.push({
        length, volume: data[b+25],
        finetune: ft>7?ft-16:ft,
        loopStart: (data[b+26]<<8|data[b+27])*2,
        loopLength: (data[b+28]<<8|data[b+29])*2,
      });
    }
    mod.songLength = data[950]||1;
    mod.patternOrder = Array.from(data.slice(952,1080));
    const maxPat = Math.max(...mod.patternOrder.slice(0,mod.songLength))+1;
    let off = 1084;
    mod.patterns = [];
    for (let p=0;p<maxPat;p++) {
      const pat = [];
      for (let r=0;r<64;r++) {
        const row = [];
        for (let c=0;c<mod.channels;c++) {
          const b0=data[off],b1=data[off+1],b2=data[off+2],b3=data[off+3]; off+=4;
          row.push({sample:(b0&0xF0)|(b2>>4),period:((b0&0xF)<<8)|b1,effect:b2&0xF,param:b3});
        }
        pat.push(row);
      }
      mod.patterns.push(pat);
    }
    mod.sampleData = [];
    for (let i=0;i<31;i++) {
      const len = mod.instruments[i].length;
      mod.sampleData.push(new Int8Array(buffer,off,len));
      off += len;
    }
    return mod;
  }

  function buildBuffers() {
    _sampleBuffers = [];
    for (let i=0;i<_mod.instruments.length;i++) {
      const inst = _mod.instruments[i];
      const data = _mod.sampleData[i];
      if (!data||data.length===0) { _sampleBuffers.push(null); continue; }
      const buf = _ctx.createBuffer(1, data.length, _ctx.sampleRate);
      const ch = buf.getChannelData(0);
      for (let j=0;j<data.length;j++) ch[j] = data[j]/128.0;
      _sampleBuffers.push(buf);
    }
  }

  function makeCh() {
    return {
      sample:0, period:0, volume:64, finetune:0,
      slideTarget:0, slideSpeed:0,
      vibratoPos:0, vibratoSpeed:0, vibratoDepth:0,
      volSlide:0, slideUp:0, slideDown:0,
      loopRow:0, loopCount:-1,
      source:null, gainNode:null,
    };
  }

  function stopCh(ch) {
    if (ch.source) { try{ch.source.stop();}catch(e){} ch.source.disconnect(); ch.source=null; }
    if (ch.gainNode) { ch.gainNode.disconnect(); ch.gainNode=null; }
  }

  function triggerNote(ch, note, when) {
    const {sample,period,effect,param} = note;
    if (sample>0&&sample<=31) {
      ch.sample = sample-1;
      ch.volume = _mod.instruments[ch.sample].volume;
      ch.finetune = _mod.instruments[ch.sample].finetune;
    }
    if (effect===3) { if (period>0) ch.slideTarget=period; return; }
    const usePeriod = period>0?period:ch.period;
    if (!usePeriod) return;
    ch.period = usePeriod;
    stopCh(ch);
    const buf = _sampleBuffers[ch.sample];
    if (!buf) return;
    const inst = _mod.instruments[ch.sample];
    const src = _ctx.createBufferSource();
    src.buffer = buf;
    if (inst.loopLength>2) {
      src.loop=true;
      src.loopStart=inst.loopStart/_ctx.sampleRate;
      src.loopEnd=(inst.loopStart+inst.loopLength)/_ctx.sampleRate;
    }
    const freq = periodToFreq(usePeriod);
    if (ch.finetune) {
      src.playbackRate.value = freq*Math.pow(2,ch.finetune/(12*8))/_ctx.sampleRate;
    } else {
      src.playbackRate.value = freq/_ctx.sampleRate;
    }
    const g = _ctx.createGain();
    g.gain.value = ch.volume/64;
    src.connect(g); g.connect(_gain);
    const off = (effect===9?param*256:0);
    src.start(when, Math.min(off/_ctx.sampleRate, buf.duration-0.001));
    ch.source=src; ch.gainNode=g;
  }

  let _jumpOrder=-1, _jumpRow=-1, _patBreak=false, _patDelay=0;

  function applyFx(ch, effect, param, tick, when) {
    const x=(param>>4)&0xF, y=param&0xF;
    if (tick===0) {
      switch(effect) {
        case 0xC: ch.volume=Math.min(64,param); if(ch.gainNode) ch.gainNode.gain.setValueAtTime(ch.volume/64,when); break;
        case 0xA: if(param) ch.volSlide=param; break;
        case 0x1: if(param) ch.slideUp=param; break;
        case 0x2: if(param) ch.slideDown=param; break;
        case 0x3: if(param) ch.slideSpeed=param; break;
        case 0x4: if(x) ch.vibratoSpeed=x; if(y) ch.vibratoDepth=y; break;
        case 0xB: _jumpOrder=param; _jumpRow=0; break;
        case 0xD: _jumpRow=x*10+y; _patBreak=true; break;
        case 0xF: if(param<0x20){_speed=param||1;}else{_bpm=param;} break;
        case 0xE:
          switch(x) {
            case 0x1: ch.period=Math.max(113,ch.period-y); if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when); break;
            case 0x2: ch.period=Math.min(856,ch.period+y); if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when); break;
            case 0x5: ch.finetune=y>7?y-16:y; break;
            case 0x6:
              if(y===0){ch.loopRow=_row;}
              else{
                if(ch.loopCount<0)ch.loopCount=y;
                else ch.loopCount--;
                if(ch.loopCount>0){_jumpRow=ch.loopRow;_patBreak=true;}
                else ch.loopCount=-1;
              }
              break;
            case 0xA: ch.volume=Math.min(64,ch.volume+y); if(ch.gainNode)ch.gainNode.gain.setValueAtTime(ch.volume/64,when); break;
            case 0xB: ch.volume=Math.max(0,ch.volume-y); if(ch.gainNode)ch.gainNode.gain.setValueAtTime(ch.volume/64,when); break;
          }
          break;
      }
    } else {
      switch(effect) {
        case 0x0:
          if(param&&ch.source&&ch.period){
            const arps=[0,x,y],semi=arps[tick%3];
            ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)*Math.pow(2,semi/12)/_ctx.sampleRate,when);
          }
          break;
        case 0x1:
          if(ch.slideUp){ch.period=Math.max(113,ch.period-ch.slideUp);if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when);} break;
        case 0x2:
          if(ch.slideDown){ch.period=Math.min(856,ch.period+ch.slideDown);if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when);} break;
        case 0x3:
          if(ch.slideTarget>0){
            if(ch.period<ch.slideTarget)ch.period=Math.min(ch.slideTarget,ch.period+ch.slideSpeed);
            else ch.period=Math.max(ch.slideTarget,ch.period-ch.slideSpeed);
            if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when);
          }
          break;
        case 0x4:
          ch.vibratoPos=(ch.vibratoPos+ch.vibratoSpeed)&63;
          if(ch.source&&ch.period){
            const vib=Math.sin(ch.vibratoPos*Math.PI/32)*ch.vibratoDepth;
            ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period+vib)/_ctx.sampleRate,when);
          }
          break;
        case 0xA:
        case 0x5:
        case 0x6: {
          const vs=ch.volSlide;
          if(vs>>4)ch.volume=Math.min(64,ch.volume+(vs>>4));
          else ch.volume=Math.max(0,ch.volume-(vs&0xF));
          if(ch.gainNode)ch.gainNode.gain.setValueAtTime(ch.volume/64,when);
          if(effect===0x5&&ch.slideTarget>0){
            if(ch.period<ch.slideTarget)ch.period=Math.min(ch.slideTarget,ch.period+ch.slideSpeed);
            else ch.period=Math.max(ch.slideTarget,ch.period-ch.slideSpeed);
            if(ch.source)ch.source.playbackRate.setValueAtTime(periodToFreq(ch.period)/_ctx.sampleRate,when);
          }
          break;
        }
        case 0xE:
          if(x===0xC&&tick===y){ch.volume=0;if(ch.gainNode)ch.gainNode.gain.setValueAtTime(0,when);} break;
      }
    }
  }

  function scheduleRows() {
    if (!_playing||!_mod) return;
    const now = _ctx.currentTime;
    const ahead = now+SCHEDULE_AHEAD;
    while (_nextRowTime<ahead) {
      const when = _nextRowTime;
      const tickDur = 2.5/_bpm;
      const rowDur = _speed*tickDur;
      const patIdx = _mod.patternOrder[_order%_mod.songLength];
      const pattern = _mod.patterns[patIdx];
      if (!pattern){_playing=false;return;}
      const row = pattern[_row];
      _jumpOrder=-1; _jumpRow=-1; _patBreak=false;
      // Tick 0 — trigger notes
      for (let c=0;c<_mod.channels;c++) {
        const note=row[c];
        if(note.sample>0||note.period>0) triggerNote(_channels[c],note,when);
        if(note.effect>0||note.param>0) applyFx(_channels[c],note.effect,note.param,0,when);
      }
      // Remaining ticks
      for (let t=1;t<_speed;t++) {
        const tw=when+t*tickDur;
        for (let c=0;c<_mod.channels;c++) {
          const note=row[c];
          applyFx(_channels[c],note.effect,note.param,t,tw);
        }
      }
      _nextRowTime+=rowDur;
      // Advance position
      if (_jumpOrder>=0) {
        _order=_jumpOrder; _row=0;
      } else if (_patBreak) {
        _order=(_order+1)%_mod.songLength; _row=Math.min(_jumpRow<0?0:_jumpRow,63);
      } else {
        _row++;
        if (_row>=64) { _row=0; _order=(_order+1)%_mod.songLength; }
      }
    }
  }

  function init(audioCtx) {
    _ctx = audioCtx;
    if (!_gain) {
      _gain = _ctx.createGain();
      _gain.gain.value = 0.72;
      _gain.connect(_ctx.destination);
    }
  }

  function load(arrayBuffer) {
    _mod = parseMOD(arrayBuffer);
    if (_ctx) buildBuffers();
  }

  function play() {
    if (!_mod||!_ctx) return;
    if (!_sampleBuffers.length) buildBuffers();
    stop();
    _order=0; _row=0; _speed=6; _bpm=125;
    _channels = Array.from({length:_mod.channels},makeCh);
    _playing=true;
    _gain.gain.cancelScheduledValues(_ctx.currentTime);
    _gain.gain.setValueAtTime(0,_ctx.currentTime);
    _gain.gain.linearRampToValueAtTime(0.72,_ctx.currentTime+1.2);
    _nextRowTime=_ctx.currentTime+0.05;
    scheduleRows();
    _timerId=setInterval(scheduleRows,SCHEDULE_INTERVAL);
  }

  function stop() {
    _playing=false;
    if (_timerId){clearInterval(_timerId);_timerId=null;}
    _channels.forEach(stopCh);
  }

  function fadeOut(dur=1.5) {
    if (!_gain||!_ctx) return;
    _gain.gain.cancelScheduledValues(_ctx.currentTime);
    _gain.gain.setValueAtTime(_gain.gain.value,_ctx.currentTime);
    _gain.gain.linearRampToValueAtTime(0,_ctx.currentTime+dur);
    setTimeout(stop, dur*1000+100);
  }

  function isReady() { return !!_mod; }

  return {init, load, play, stop, fadeOut, isReady};
})();


